import{c as r,a7 as e,y as a,B as i}from"./chunks/framework.3cjvm90C.js";const d=JSON.parse('{"title":"A2C 优势演员-评论家算法","description":"介绍 A2C 算法如何结合价值函数与策略梯度降低方差","frontmatter":{"title":"A2C 优势演员-评论家算法","description":"介绍 A2C 算法如何结合价值函数与策略梯度降低方差"},"headers":[],"relativePath":"rlwiki/hfrlclass/ch5_a2c.md","filePath":"rlwiki/hfrlclass/ch5_a2c.md","lastUpdated":1782448598000}'),n={name:"rlwiki/hfrlclass/ch5_a2c.md"};function o(c,t,s,l,g,p){return e(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="a2c" tabindex="-1">A2C <a class="header-anchor" href="#a2c" aria-label="Permalink to “A2C”">​</a></h1><p>在第 4 单元中，我们学习了第一个基于策略的算法，<strong>Reinforce</strong>。在基于策略的方法中，<strong>我们的目标是直接优化策略而不使用价值函数</strong>。更准确地说， Reinforce 是<em>Policy-Based Methods</em>子类的一部分，称为<em>Policy-Gradient methods</em>。该子类通过<strong>使用 Gradient Ascent 估计最优策略的权重</strong>直接优化策略。</p><p>我们看到 Reinforce 效果还不错。然而，因为使用蒙特卡洛抽样来估计回报（用一整个 Episode 来计算回报），<strong>在策略梯度估计上方差非常大</strong>。</p><p>策略梯度估计是<strong>回报增长最快的方向</strong>。也就是，如何更新我们的策略权重，使得带来良好回报的动作更有可能被采纳。然而，蒙特卡洛采样带来的高方差会<strong>导致训练速度变慢，因为我们需要大量样本来减轻这一问题</strong>。</p><p>今天我们将研究<strong>Actor-Critic 方法</strong>，这是一种混合的架构，结合了基于价值和基于策略的方法，通过减少方差来帮助稳定训练：</p><ul><li>Actor：控制<strong>智能体行为方式</strong>（基于策略的方法）</li><li>Critic：衡量**所采取动作的好坏 **（基于价值的方法）</li></ul><p>我们将研究其中一种称为 Advantage Actor Critic (A2C) 的混合方法，并动手从零开始实现这一算法。</p><h2 id="reinforce-算法的方差问题" tabindex="-1">Reinforce 算法的方差问题 <a class="header-anchor" href="#reinforce-算法的方差问题" aria-label="Permalink to “Reinforce 算法的方差问题”">​</a></h2><p>在 Reinforce 中，我们希望<strong>增加轨迹中动作的概率与回报的高低成正比</strong>。</p><img src="https://huggingface.co/blog/assets/85_policy_gradient/pg.jpg" alt="加强" style="zoom:25%;"><ul><li>如果<strong>回报高</strong>，<strong>将推高</strong>（状态，动作）组合的概率。</li><li>否则，如果<strong>回报很低</strong>，则<strong>降低</strong>（状态，动作）组合的概率。</li></ul><p>回报 $R(\\tau)$是使用蒙特卡洛采样计算的。我们收集智能体和环境交互的轨迹并计算折扣回报，<strong>并使用回报分数来增加或减少在该轨迹中采取的每个动作的概率</strong>。如果回报高，所有动作都将通过增加采取动作的可能性来“加强”。$R(\\tau) = R_{t+1} + \\gamma R_{t+2} + \\gamma^2R_{t+3} + ... $</p><p>这种方法的优点是： <strong>这种方法的估计是无偏的。因为我们没有估计回报</strong>，只是通过采样获得的真实回报来计算。</p><p>但是由于环境的随机性和策略的随机性，不同<strong>轨迹可能导致不同的回报</strong>， 因此带来的方差很高。因此，相同的起始状态可能导致截然不同的回报。正因为如此，<strong>从同一状态开始的回报在不同的 Episode 中可能会有很大差异</strong>。</p><img src="https://huggingface.co/blog/assets/89_deep_rl_a2c/variance.jpg" alt="方差" style="zoom:25%;"><p><strong>解决方案是通过使用大量轨迹</strong>来减轻方差 ，希望在任何一个轨迹中引入的方差都将总体减少，并提供一个“真实”的回报估计。</p><p>然而，增加 Batch_size 会显着<strong>降低采样效率</strong>。所以我们需要找到额外的机制来减少方差。</p><p>如果你想更深入地研究深度强化学习中的方差和偏差平衡问题，可以查看这两篇文章：</p><ul><li><a href="https://blog.mlreview.com/making-sense-of-the-bias-variance-trade-off-in-deep-reinforcement-learning-79cf1e83d565" target="_blank" rel="noreferrer">理解（深度）强化学习中的偏差/方差平衡</a></li><li><a href="https://www.endtoend.ai/blog/bias-variance-tradeoff-in-reinforcement-learning/" target="_blank" rel="noreferrer">强化学习中的偏差方差平衡</a></li></ul><hr><h2 id="actor-critic-ac" tabindex="-1">Actor Critic (AC) <a class="header-anchor" href="#actor-critic-ac" aria-label="Permalink to “Actor Critic (AC)”">​</a></h2><h3 id="使用-actor-critic-方法减少方差" tabindex="-1">使用 Actor-Critic 方法减少方差 <a class="header-anchor" href="#使用-actor-critic-方法减少方差" aria-label="Permalink to “使用 Actor-Critic 方法减少方差”">​</a></h3><p>减少 Reinforce 算法的方差并更快更好地训练智能体的解决方案是结合基于策略和基于价值的方法：<em>Actor-Critic 方法</em>。</p><p>要了解 Actor-Critic，请想象您玩电子游戏。你可以和一个朋友一起玩，他会给你一些反馈。你是 Actor，你的朋友是 Critic。</p><img src="https://huggingface.co/blog/assets/89_deep_rl_a2c/ac.jpg" alt="ActorCritic" style="zoom:33%;"><p>一开始你不知道怎么玩，<strong>所以你随机尝试一些动作</strong>。Critic 观察您的行为并<strong>提供反馈</strong>。</p><p>从这些反馈中学习， <strong>您将更新您的策略并更好地玩这个游戏。</strong></p><p>另一方面，您的朋友（Critic）也会更新他们提供反馈的方式，以便下次可以做得更好。</p><p>这就是 Actor-Critic 背后的想法。我们学习了两个函数逼近：</p><ul><li><strong>控制我们的智能体行为方式</strong>的<em>策略函数</em>：$\\pi_{\\theta}(s,a)$</li><li>通过衡量所采取的动作好坏的来协助策略更新的<em>价值函数：</em>$\\hat{q}_{w}(s,a)$</li></ul><h3 id="actor-critic-过程" tabindex="-1">Actor-Critic 过程 <a class="header-anchor" href="#actor-critic-过程" aria-label="Permalink to “Actor-Critic 过程”">​</a></h3><p>现在我们已经从大局层面理解了 Actor Critic，接下来让我们更深入地了解 Actor 和 Critic 在训练过程中是如何进行改进和优化的。</p><p>正如我们所见， Actor-Critic 方法有两个函数近似（两个神经网络）：</p><ul><li><em>Actor</em>，由 theta 参数化的<strong>策略函数：</strong>$\\pi_{\\theta}(s,a)$</li><li><em>Critic</em>，由 w 参数化的<strong>价值函数：</strong>$\\hat{q}_{w}(s,a)$</li></ul><p>让我们看看训练过程，了解 Actor 和 Critic 是如何被优化的：</p><ul><li>在每个时间步 t，我们得到当前的来自环境状态 $S_t$ ，并将<strong>其作为输入传递给我们的 Actor 和 Critic</strong>。</li><li>我们的策略获取状态 $S_t$ 并<strong>输出一个动作</strong> $A_t$.</li></ul><img src="https://huggingface.co/blog/assets/89_deep_rl_a2c/step1.jpg" alt="Step 1 ActorCritic" style="zoom:25%;"><ul><li>Critic 也将该动作作为输入，并使用$S_t$ 和 $A_t$，<strong>计算在该状态下采取该动作的值： Q 值</strong>。</li></ul><img src="https://huggingface.co/blog/assets/89_deep_rl_a2c/step2.jpg" alt="Step 2 ActorCritic" style="zoom:25%;"><ul><li>环境执行动作 $A_t$ 并输出一个新的状态 $S_{t+1}$ 和奖励 $R_{t+1}$.</li></ul><img src="https://huggingface.co/blog/assets/89_deep_rl_a2c/step3.jpg" alt="步骤 3 ActorCritic" style="zoom:25%;"><ul><li>Actor 使用 Q 值更新其策略参数。</li></ul><img src="https://huggingface.co/blog/assets/89_deep_rl_a2c/step4.jpg" alt="步骤 4 ActorCritic" style="zoom:25%;"><ul><li>更新完参数的 Actor，在给定新状态 $S_{t+1}$下产生了下一步要采取的动作 $A_{t+1}$ 。</li><li>然后 Critic 更新它的价值函数的参数。</li></ul><img src="https://huggingface.co/blog/assets/89_deep_rl_a2c/step5.jpg" alt="步骤 5 ActorCritic" style="zoom:25%;"><h2 id="advantage-actorcritic-a2c" tabindex="-1">Advantage ActorCritic (A2C) <a class="header-anchor" href="#advantage-actorcritic-a2c" aria-label="Permalink to “Advantage ActorCritic (A2C)”">​</a></h2><p>我们可以通过<strong>使用 Advantage function 作为 Critic 而不是 Action value function 来</strong> 进一步稳定学习。</p><p>这个想法是 Advantage 函数计算<strong>在一个状态下采取该动作与该状态的平均值的相对优势</strong>。它通过从状态动作对中减去状态的平均值：</p><img src="https://huggingface.co/blog/assets/89_deep_rl_a2c/advantage1.jpg" alt="优势功能" style="zoom:25%;"><p>换句话说，这个函数计算<strong>的是如果我们在那个状态下采取这个动作，我们得到的额外奖励与我们在那个状态下得到的平均奖励相比</strong>的优势。</p><p>而额外的奖励则是超出该状态预期值的。</p><ul><li>如果 A(s,a) &gt; 0：我们的梯度被<strong>推向那个方向</strong>。</li><li>如果 A(s,a) &lt; 0 （我们的动作价值比那个状态的平均值要差），<strong>我们的梯度被推向相反的方向</strong>。</li></ul><p>实现这个优势函数的问题在于它需要两个价值函数 $Q(s,a)$ 和 $V(s)$. 幸运的是， <strong>我们可以使用 TD 误差作为优势函数的良好估计量。</strong></p><img src="https://huggingface.co/blog/assets/89_deep_rl_a2c/advantage2.jpg" alt="优势功能" style="zoom:25%;"><p>既然您已经研究了 Advantage Actor Critic （A2C）背后的理论，接下来我们将使用 Pytorch 从头实现这一算法。</p><h2 id="补充阅读" tabindex="-1">补充阅读 <a class="header-anchor" href="#补充阅读" aria-label="Permalink to “补充阅读”">​</a></h2><h3 id="bias-variance-tradeoff-in-reinforcement-learning" tabindex="-1">Bias-variance tradeoff in Reinforcement Learning <a class="header-anchor" href="#bias-variance-tradeoff-in-reinforcement-learning" aria-label="Permalink to “Bias-variance tradeoff in Reinforcement Learning”">​</a></h3><p>如果你想更深入地研究深度强化学习中的方差和偏差权衡问题，你可以查看这两篇文章：</p><ul><li><a href="https://blog.mlreview.com/making-sense-of-the-bias-variance-trade-off-in-deep-reinforcement-learning-79cf1e83d565" target="_blank" rel="noreferrer">Making Sense of the Bias / Variance Trade-off in (Deep) Reinforcement Learning</a></li><li><a href="https://www.endtoend.ai/blog/bias-variance-tradeoff-in-reinforcement-learning/" target="_blank" rel="noreferrer">Bias-variance Tradeoff in Reinforcement Learning</a></li></ul><h3 id="advantage-functions" tabindex="-1">Advantage Functions <a class="header-anchor" href="#advantage-functions" aria-label="Permalink to “Advantage Functions”">​</a></h3><ul><li>[Advantage Functions, SpinningUp RL](<a href="https://spinningup.openai.com/en/latest/spinningup/rl_intro.html?highlight=advantage" target="_blank" rel="noreferrer">https://spinningup.openai.com/en/latest/spinningup/rl_intro.html?highlight=advantage</a> functio#advantage-functions)</li></ul><h3 id="actor-critic" tabindex="-1">Actor Critic <a class="header-anchor" href="#actor-critic" aria-label="Permalink to “Actor Critic”">​</a></h3><ul><li><a href="https://www.youtube.com/watch?v=AKbX1Zvo7r8" target="_blank" rel="noreferrer">Foundations of Deep RL Series, L3 Policy Gradients and Advantage Estimation by Pieter Abbeel</a></li><li><a href="https://arxiv.org/abs/1602.01783v2" target="_blank" rel="noreferrer">A2C Paper: Asynchronous Methods for Deep Reinforcement Learning</a></li></ul>',63)])])}const f=r(n,[["render",o]]);export{d as __pageData,f as default};
